// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC721/IERC721.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC721/IERC721Receiver.sol";

contract LandEscrow is ReentrancyGuard, IERC721Receiver {
    IERC721 public landNFT;

    struct Trade {
        address buyer;
        address seller;
        uint256 tokenId;
        uint256 price;
        bool isFunded;
        bool isNftDeposited;
        bool isCompleted;
    }

    // Mapping from tradeId (can be generated off-chain or sequentially) to Trade
    mapping(string => Trade) public trades;

    event TradeInitiated(string tradeId, address indexed buyer, address indexed seller, uint256 tokenId, uint256 price);
    event FundsDeposited(string tradeId, address indexed buyer, uint256 amount);
    event NftDeposited(string tradeId, address indexed seller, uint256 tokenId);
    event TradeExecuted(string tradeId, address indexed buyer, address indexed seller, uint256 tokenId, uint256 price);
    event TradeCancelled(string tradeId, address indexed buyer, address indexed seller);

    constructor(address _landNFTAddress) {
        landNFT = IERC721(_landNFTAddress);
    }

    /**
     * @dev Initialize a trade with the agreed terms and deposit funds. 
     * Called by the buyer.
     */
    function depositFunds(string memory tradeId, address seller, uint256 tokenId) external payable nonReentrant {
        require(msg.value > 0, "Price must be greater than zero");
        require(trades[tradeId].buyer == address(0), "Trade already exists");

        trades[tradeId] = Trade({
            buyer: msg.sender,
            seller: seller,
            tokenId: tokenId,
            price: msg.value,
            isFunded: true,
            isNftDeposited: false,
            isCompleted: false
        });

        emit TradeInitiated(tradeId, msg.sender, seller, tokenId, msg.value);
        emit FundsDeposited(tradeId, msg.sender, msg.value);
    }

    /**
     * @dev Deposit the NFT into the escrow.
     * Called by the seller after approving the Escrow contract.
     */
    function depositNFT(string memory tradeId) external nonReentrant {
        Trade storage trade = trades[tradeId];
        require(trade.buyer != address(0), "Trade does not exist");
        require(!trade.isCompleted, "Trade already completed");
        require(msg.sender == trade.seller, "Only seller can deposit NFT");
        require(!trade.isNftDeposited, "NFT already deposited");

        trade.isNftDeposited = true;
        landNFT.safeTransferFrom(msg.sender, address(this), trade.tokenId);

        emit NftDeposited(tradeId, msg.sender, trade.tokenId);
    }

    /**
     * @dev Execute the trade. Can be called by anyone once both assets are deposited.
     */
    function executeTrade(string memory tradeId) external nonReentrant {
        Trade storage trade = trades[tradeId];
        require(trade.isFunded, "Trade is not funded");
        require(trade.isNftDeposited, "NFT is not deposited");
        require(!trade.isCompleted, "Trade already completed");

        // Mark as completed
        trade.isCompleted = true;

        // Transfer NFT from Escrow to Buyer
        landNFT.safeTransferFrom(address(this), trade.buyer, trade.tokenId);

        // Transfer funds to Seller
        (bool success, ) = payable(trade.seller).call{value: trade.price}("");
        require(success, "Transfer failed");

        emit TradeExecuted(tradeId, trade.buyer, trade.seller, trade.tokenId, trade.price);
    }

    /**
     * @dev Cancel the trade and refund the parties. Can be called by buyer or seller.
     */
    function cancelTrade(string memory tradeId) external nonReentrant {
        Trade storage trade = trades[tradeId];
        require(trade.buyer != address(0), "Trade does not exist");
        require(!trade.isCompleted, "Trade already completed");
        require(msg.sender == trade.buyer || msg.sender == trade.seller, "Only buyer or seller can cancel");

        trade.isCompleted = true;

        // Refund buyer if funded
        if (trade.isFunded) {
            trade.isFunded = false;
            (bool success, ) = payable(trade.buyer).call{value: trade.price}("");
            require(success, "Refund failed");
        }

        // Refund seller if NFT deposited
        if (trade.isNftDeposited) {
            trade.isNftDeposited = false;
            landNFT.safeTransferFrom(address(this), trade.seller, trade.tokenId);
        }

        emit TradeCancelled(tradeId, trade.buyer, trade.seller);
    }

    /**
     * @dev Required for the contract to receive ERC721 tokens via safeTransferFrom
     */
    function onERC721Received(address, address, uint256, bytes calldata) external pure override returns (bytes4) {
        return this.onERC721Received.selector;
    }
}
